"use strict";(globalThis.webpackChunknew_website=globalThis.webpackChunknew_website||[]).push([[3210],{53210(e,t,r){r.r(t),r.d(t,{assets:()=>h,contentTitle:()=>i,default:()=>y,frontMatter:()=>a,metadata:()=>o,toc:()=>l});var o=r(64748),s=r(74848),n=r(28453);const a={title:"Are you really expected to run five type-checkers now?",description:"Library maintainers may feel overwhelmed by the plurality of type checkers that exist. We offer some guidance on how to focus their efforts where they matter most.",slug:"too-many-type-checkers",authors:["marcogorelli"],tags:["typechecking","news"],hide_table_of_contents:!1},i=void 0,h={authorsImageUrls:[void 0]},l=[{value:"The type checking that matters most (and why you&#39;ve probably got it backwards)",id:"the-type-checking-that-matters-most-and-why-youve-probably-got-it-backwards",level:2},{value:"The Polars story",id:"the-polars-story",level:2},{value:"What about my source code? Why are there so many type checkers anyway?",id:"what-about-my-source-code-why-are-there-so-many-type-checkers-anyway",level:2},{value:"The bottom line",id:"the-bottom-line",level:2}];function c(e){const t={a:"a",code:"code",h2:"h2",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,n.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:"Mypy, Pyrefly, Pyright, ty, Zuban, and possibly more that will come in the future... how are library maintainers expected to cope?"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"TL;DR"}),": Prioritise running as many type-checkers as possible on your test suite. Run at least one on your source code."]}),"\n",(0,s.jsx)(t.h2,{id:"the-type-checking-that-matters-most-and-why-youve-probably-got-it-backwards",children:"The type checking that matters most (and why you've probably got it backwards)"}),"\n",(0,s.jsxs)(t.p,{children:["If you only read one section of this blog post, please make it this one. Because this is where a lot of packages get it wrong. It's common to see packages run type checkers on their source code and to leave their tests untyped. ",(0,s.jsx)(t.strong,{children:"That approach has it backwards"}),"."]}),"\n",(0,s.jsxs)(t.p,{children:["Suppose you maintain a Python package. As a hypothetical user of your code, I don't particularly care about your internal development practices. Whether you use ",(0,s.jsx)(t.code,{children:"ruff format"})," or ",(0,s.jsx)(t.code,{children:"black"}),", how you sort your imports, whether you use ",(0,s.jsx)(t.code,{children:"pytest"})," or ",(0,s.jsx)(t.code,{children:"unittest"}),", none of this affects me. What I do care about is your public API and my experience interacting with it."]}),"\n",(0,s.jsx)(t.p,{children:"When you run a type-checker on your internal source code, you're mostly testing your internal logic. You can do that with whichever type checker you prefer, that's your choice. Which type-checker your users use, on the other hand, isn't."}),"\n",(0,s.jsx)(t.p,{children:"By running as many type-checkers as possible over your test suite, you ensure that your package's public API works well for as many of your users as possible."}),"\n",(0,s.jsx)(t.h2,{id:"the-polars-story",children:"The Polars story"}),"\n",(0,s.jsxs)(t.p,{children:["Polars is a modern dataframe library which, since its launch in 2020, has been taking the data science world by storm. As a heavy user of the library, I was very interested in making its developer experience even better. If Polars' types are accurate, then as a user I get better auto-complete, documentation, and ",(0,s.jsx)(t.a,{href:"https://pyrefly.org/blog/surprising-errors/",children:"protection from certain classes of bugs"}),". What would it take to add Pyrefly to Polars' continuous integration jobs?"]}),"\n",(0,s.jsxs)(t.p,{children:["I started investigating this, and quickly ran into some roadblocks. Pyrefly is generally stricter than mypy, so it required rewriting parts of the codebase or adding more explicit type annotations when instantiating variables. Furthermore, I encountered some bugs in Pyrefly, and encouragingly enough, fixes for the vast majority of them were shipped with the highly anticipated ",(0,s.jsx)(t.a,{href:"https://pyrefly.org/blog/v1.0/",children:"v1 release"}),". I think it was worth it, especially as it ",(0,s.jsx)(t.a,{href:"https://github.com/pola-rs/polars/issues/27620",children:"uncovered a medium-priority bug"}),", but I did have to ask myself whether going through this for another three type-checkers would be."]}),"\n",(0,s.jsxs)(t.p,{children:["To illustrate this point, let's look at the function ",(0,s.jsx)(t.code,{children:"DataType.__eq__"}),". In Python, any method ",(0,s.jsx)(t.code,{children:"__eq__"})," is expected to return ",(0,s.jsx)(t.code,{children:"bool"}),", and if it doesn't, then we need to explicitly tell type-checkers to ignore the type error. This function in Polars can also return different types depending on the inputs, thus requiring ",(0,s.jsx)(t.a,{href:"https://typing.python.org/en/latest/spec/overload.html",children:"overloads"}),". To get this function to satisfy all of mypy, Pyrefly, and ty, we need to write:"]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-py",children:"    @overload  # type: ignore[override]\n    def __eq__(  # pyrefly: ignore[bad-override]\n        self, other: pl.DataTypeExpr\n    ) -> pl.Expr: ...\n\n    @overload\n    def __eq__(self, other: PolarsDataType) -> bool: ...\n\n    def __eq__(self, other: pl.DataTypeExpr | PolarsDataType) -> pl.Expr | bool:  # ty: ignore[invalid-method-override]  # pyright: ignore[reportIncompatibleMethodOverride]\n"})}),"\n",(0,s.jsx)(t.p,{children:"Wow, that's 4 different type-ignore comments for just 7 lines of code! You can see how a codebase quickly becomes polluted with such comments, or with workarounds to deal with different type-checkers' quirks. I don't think any library maintainer wants a codebase that looks like that. Surely there's a better way?"}),"\n",(0,s.jsxs)(t.p,{children:["Instead of putting all your internals through multiple type-checkers, why not start by testing that all major type-checkers can be used with your library's public API? That's much more useful, so it's easier to justify spending time on it. But it's also easier, because you're just ensuring that, if your library gets used as-intended, then there are no type errors. In the case of ",(0,s.jsx)(t.code,{children:"DataType.__eq__"}),", there's a test for it that looks like this:"]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-py",children:'DTYPE_TEMPORAL_UNITS: Final[frozenset[TimeUnit]] = frozenset(["ns", "us", "ms"])\n\ndef test_dtype_time_units() -> None:\n    # check (in)equality behaviour of temporal types that take units\n    for time_unit in DTYPE_TEMPORAL_UNITS:\n        assert pl.Datetime == pl.Datetime(time_unit)\n        assert pl.Duration == pl.Duration(time_unit)\n\n        assert pl.Datetime(time_unit) == pl.Datetime\n        assert pl.Duration(time_unit) == pl.Duration\n'})}),"\n",(0,s.jsx)(t.p,{children:"What's pleasing to see is that mypy, Pyrefly, Pyright, ty, Zuban all type-check this fine without reporting any errors! So even though the type-checkers disagree a bit on how the implementation should be written, they all agree about the effects on the public API. And that's what your users care about!"}),"\n",(0,s.jsxs)(t.p,{children:["Getting Pyrefly to run on the whole Polars test suite was relatively painless, you can check out the ",(0,s.jsx)(t.a,{href:"https://github.com/pola-rs/polars/pull/27459",children:"PR"})," to verify this. To ease Polars' own internal development, we've also been exploring using Pyrefly on their source code, though that is a ",(0,s.jsx)(t.a,{href:"https://github.com/pola-rs/polars/issues/27049",children:"larger effort"})," and is being tackled incrementally."]}),"\n",(0,s.jsx)(t.h2,{id:"what-about-my-source-code-why-are-there-so-many-type-checkers-anyway",children:"What about my source code? Why are there so many type checkers anyway?"}),"\n",(0,s.jsxs)(t.p,{children:["The ",(0,s.jsx)(t.a,{href:"https://typing.python.org/en/latest/spec/",children:"typing spec"})," outlines a standard set of rules that type checkers are expected to adhere to. There are aspects of it that are a bit hazy, however, such as in cases where users under-specify typing information. In those cases, different type checkers make different design decisions:"]}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Some choose to be as strict as possible, emitting false-positives if necessary, but doing as much as possible to guard you from potential bugs."}),"\n",(0,s.jsx)(t.li,{children:"Others are more lenient and allow you to add type information to your codebase more gradually."}),"\n"]}),"\n",(0,s.jsxs)(t.p,{children:["When it comes to type-checking your source code, it's good to ask yourself where on the strict vs lenient spectrum you want to be. Pyrefly is not only strict (though ",(0,s.jsx)(t.a,{href:"https://pyrefly.org/en/docs/configuration/#configuration-options",children:"this can be configured"}),"), but also ",(0,s.jsx)(t.a,{href:"https://pyrefly.org/blog/speed-and-memory-comparison/",children:"fast"})," and ",(0,s.jsx)(t.a,{href:"https://pyrefly.org/blog/typing-conformance-comparison/",children:"conformant"}),", making it an excellent choice. If you try it out on your projects and run into any issues, ",(0,s.jsx)(t.a,{href:"https://github.com/facebook/pyrefly/issues",children:"please report them"})," so that both you and all its other users can benefit from fixes!"]}),"\n",(0,s.jsx)(t.h2,{id:"the-bottom-line",children:"The bottom line"}),"\n",(0,s.jsx)(t.p,{children:"There are 5 Python type-checkers which get attention these days: mypy, Pyrefly, Pyright, ty, Zuban. Library maintainers may rightfully feel like running all 5 of them over their source code is too much maintenance effort and requires polluting their code with too many type-ignore comments. We have made the case that such effort would be better spent by running multiple type-checkers over their tests instead, as that will test how well the library can be type-checked when users interact with it."})]})}function y(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(c,{...e})}):c(e)}},28453(e,t,r){r.d(t,{R:()=>a,x:()=>i});var o=r(96540);const s={},n=o.createContext(s);function a(e){const t=o.useContext(n);return o.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),o.createElement(n.Provider,{value:t},e.children)}},64748(e){e.exports=JSON.parse('{"permalink":"/blog/too-many-type-checkers","source":"@site/blog/2026-06-03-too-many-type-checkers.md","title":"Are you really expected to run five type-checkers now?","description":"Library maintainers may feel overwhelmed by the plurality of type checkers that exist. We offer some guidance on how to focus their efforts where they matter most.","date":"2026-06-03T00:00:00.000Z","tags":[{"inline":true,"label":"typechecking","permalink":"/blog/tags/typechecking"},{"inline":true,"label":"news","permalink":"/blog/tags/news"}],"readingTime":5.18,"hasTruncateMarker":true,"authors":[{"name":"Marco Gorelli, Quansight Labs","url":"https://github.com/MarcoGorelli","key":"marcogorelli","page":null}],"frontMatter":{"title":"Are you really expected to run five type-checkers now?","description":"Library maintainers may feel overwhelmed by the plurality of type checkers that exist. We offer some guidance on how to focus their efforts where they matter most.","slug":"too-many-type-checkers","authors":["marcogorelli"],"tags":["typechecking","news"],"hide_table_of_contents":false},"unlisted":false,"nextItem":{"title":"Pyrefly v1.0 is here!","permalink":"/blog/v1.0"}}')}}]);